//-------------------------------------------------------------------------
// 세금계산서 취소 때  세무마감여부 CHECK
//-------------------------------------------------------------------------
scwin.f_CheckTaxCancelSpplyDt = async function () {
  let taxCloseYm = ica_taxCloseYm.getValue();
  let spplyYm = ica_spplyDt.getValue().substring(0, 6);
  let isTrue;
  if (taxCloseYm >= spplyYm) {
    isTrue = $c.win.confirm($p, "세무마감된 계산서를 취소할 경우에는 반드시 거래처에 수정세금계산서를 발행해야 합니다.(거래처와 합의 요함)<br><br>세금계산서 및 전표를 취소하시겠습니까?");
    if (!isTrue) {
      return;
    }
    if (ica_cancelSpplyDt.getValue() == null || ica_cancelSpplyDt.getValue() == "") {
      $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "[수정세금계산서 공급일자 ]")); //@은(는) 필수 입력 항목입니다
      ica_cancelSpplyDt.focus();
      return false;
    }
    if (!(await $c.gus.cfValidate($p, [ica_cancelSpplyDt]))) {
      ica_cancelSpplyDt.focus;
      return;
    }
  }
  return true;
};

