//-------------------------------------------------------------------------
// tr_retrieveCtrtNo에서 OnSuccess이벤트 발생시
//-------------------------------------------------------------------------
scwin.sbm_retrieveCtrtNo2_submitdone = async function (e) {
  try {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    var ctrtNoRows = ds_ctrtNo2.getTotalRow();
    if (ctrtNoRows > 0) {
      //계약번호가 서로 다른 것이 있는 경우, 선택을 default로 보여주기 위한 process
      var sameYn = "N";
      for (j = 0; j < ds_ctrtNo2.getTotalRow(); j++) {
        if ("1" == ds_ctrtNo2.getCellData(j, "mgntTrgtClntYn")) {
          sameYn = "Y";
          break;
        }
      }
      if (sameYn == "Y") {
        await $c.win.alert($p, "청구처가 관리대상 거래처 입니다.<br>거래처코드의 상태를 확인하시고, 관리거래처인 경우에는 저장할 수 없습니다.");
        scwin.clntMgntYn = 1;
        return;
      } else {
        scwin.clntMgntYn = 0;
      }
    } else {
      await $c.win.alert($p, "청구처가 관리대상 거래처 입니다.");
      return;
    }
  } catch (e) {
    console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
  }
};

